.channel-item input[type="checkbox"] {
    width: 16px;
    height: 16px;
    accent-color: #0d6efd;
}

/* ── Expandable Panel ── */
.expandable-panel {
    border: 1px solid #e9ecef;
    border-radius: 8px;
    overflow: hidden;
}

.panel-header {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: .85rem 1rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-weight: 500;
    font-size: .95rem;
    color: #495057;
    transition: background .15s;
}

.panel-header:hover {
    background: #e9ecef;
}

.expand-icon {
    font-size: .75rem;
    color: #6c757d;
}

.panel-body {
    padding: 1rem;
    border-top: 1px solid #e9ecef;
}

/* ── Sessions Table ── */
.sessions-table {
    font-size: .9rem;
}

.sessions-table th {
    font-weight: 600;
    color: #6c757d;
    border-bottom-width: 1px;
    font-size: .8rem;
    text-transform: uppercase;
    letter-spacing: .03em;
}

/* ── Confirmation Dialog ── */
.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.confirm-dialog {
    background: #fff;
    border-radius: 12px;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 8px 30px rgba(0,0,0,.15);
}

.confirm-dialog h5 {
    margin: 0 0 .75rem;
}

.confirm-dialog p {
    color: #495057;
    margin-bottom: 1rem;
}

/* ── Radio Groups ── */
.radio-group {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
}

.radio-option {
    display: flex;
    align-items: center;
    gap: .4rem;
    padding: .5rem .85rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    cursor: pointer;
    transition: border-color .15s, background .15s;
}

.radio-option:hover {
    border-color: #0d6efd;
    background: #e7f1ff;
}

.radio-option input[type="radio"] {
    accent-color: #0d6efd;
}

/* ── Appearance Preview ── */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
    margin-bottom: .5rem;
    transition: all .25s;
}

.preview-header {
    font-weight: 600;
    margin-bottom: .5rem;
    font-size: 1.1rem;
}

.preview-text {
    margin-bottom: .75rem;
}

.preview-buttons {
    display: flex;
    gap: .5rem;
}

/* Theme variants */
.preview-theme-light {
    background: #ffffff;
    color: #212529;
}

.preview-theme-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-theme-dark .btn-primary {
    background: #89b4fa;
    border-color: #89b4fa;
    color: #1e1e2e;
}

.preview-theme-dark .btn-outline-secondary {
    color: #a6adc8;
    border-color: #585b70;
}

.preview-theme-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #495057;
}

/* Font size variants */
.preview-font-small {
    font-size: .8rem;
}

.preview-font-small .preview-header {
    font-size: .95rem;
}

.preview-font-medium {
    font-size: .95rem;
}

.preview-font-large {
    font-size: 1.15rem;
}

.preview-font-large .preview-header {
    font-size: 1.35rem;
}

/* Compact */
.preview-compact {
    padding: .6rem .85rem;
}

.preview-compact .preview-header {
    margin-bottom: .25rem;
}

.preview-compact .preview-text {
    margin-bottom: .35rem;
}

/* ── Toast ── */
.toast-message {
    position: fixed;
    bottom: 1.5rem;
    right: 1.5rem;
    padding: .75rem 1.25rem;
    border-radius: 8px;
    font-weight: 500;
    color: #fff;
    z-index: 1100;
    animation: toast-in .3s ease;
    box-shadow: 0 4px 12px rgba(0,0,0,.15);
}

.toast-success {
    background: #198754;
}

.toast-error {
    background: #dc3545;
}

@@keyframes toast-in {
    from {
        opacity: 0;
        transform: translateY(10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

