    color: #1e1e2e;
}

.preview-theme-dark .btn-outline-secondary {
    color: #a6adc8;
    border-color: #585b70;
}

.preview-theme-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #495057;
}

/* Font size variants */
.preview-font-small {
    font-size: .8rem;
}

.preview-font-small .preview-header {
    font-size: .95rem;
}

.preview-font-medium {
    font-size: .95rem;
}

.preview-font-large {
    font-size: 1.15rem;
}

.preview-font-large .preview-header {
    font-size: 1.35rem;
}

/* Compact */
.preview-compact {
    padding: .6rem .85rem;
}

.preview-compact .preview-header {
    margin-bottom: .25rem;
}

.preview-compact .preview-text {
    margin-bottom: .35rem;
}

/* ── Toast ── */
.toast-message {
    position: fixed;
    bottom: 1.5rem;
    right: 1.5rem;
    padding: .75rem 1.25rem;
    border-radius: 8px;
    font-weight: 500;
    color: #fff;
    z-index: 1100;
    animation: toast-in .3s ease;
    box-shadow: 0 4px 12px rgba(0,0,0,.15);
}

.toast-success {
    background: #198754;
}

.toast-error {
    background: #dc3545;
}

@@keyframes toast-in {
    from {
        opacity: 0;
        transform: translateY(10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}
