+
+        <div class="toggle-row">
+            <div>
+                <strong>Weekly Digest</strong>
+                <p class="text-muted small mb-0">Get a weekly summary of activity</p>
+            </div>
+            <label class="toggle-switch">
+                <input type="checkbox" @bind="_editWeeklyDigest" />
+                <span class="toggle-slider"></span>
+            </label>
+        </div>
+    </div>
+
+    <h5 class="mt-4">Muted Channels</h5>
+    <p class="text-muted small">Check channels you want to mute.</p>
+    <div class="channel-list">
+        @foreach (var channel in _allChannels)
+        {
+            var isMuted = _editMutedChannels.Contains(channel);
+            <label class="channel-item">
+                <input type="checkbox" checked="@isMuted" @onchange="e => ToggleMutedChannel(channel, (bool)e.Value!)" />
+                <span>#@channel</span>
+            </label>
+        }
+    </div>
+
+    <div class="button-group">
+        <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
+            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
+            Save Preferences
+        </button>
+    </div>
+</section>; }
+
+@* ────────────── Security Section ────────────── *@
+@{ RenderFragment RenderSecuritySection() => @<section class="settings-section">
+    <h3>Security</h3>
+    <p class="section-description">Manage your password, two-factor authentication, and active sessions.</p>
+
+    @* Change Password *@
+    <div class="expandable-panel">
+        <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
+            <span>🔑 Change Password</span>
+            <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
+        </button>
+        @if (_passwordPanelOpen)
+        {
+            <div class="panel-body">
+                <div class="form-group">
+                    <label for="currentPw">Current Password</label>
+                    <input id="currentPw" type="password" class="form-control" @bind="_currentPassword" />
+                </div>
+                <div class="form-group">
+                    <label for="newPw">New Password</label>
+                    <input id="newPw" type="password" class="form-control" @bind="_newPassword" />
+                </div>
+                <div class="form-group">
+                    <label for="confirmPw">Confirm New Password</label>
+                    <input id="confirmPw" type="password" class="form-control" @bind="_confirmPassword" />
+                </div>
+                @if (!string.IsNullOrEmpty(_passwordError))
+                {
+                    <div class="text-danger small mb-2">@_passwordError</div>
+                }
+                <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
+                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
+                    Update Password
+                </button>
+            </div>
+        }
+    </div>
+
+    @* Two-Factor Authentication *@
+    <div class="toggle-row mt-4">
+        <div>
+            <strong>Two-Factor Authentication</strong>
+            <p class="text-muted small mb-0">
+                Status:
+                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
+                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
+                </span>
+            </p>
+            @if (_security?.LastPasswordChange is not null)
+            {
+                <p class="text-muted small mb-0">Last password change: @_security.LastPasswordChange.Value.ToString("MMM dd, yyyy")</p>
+            }
+        </div>
+        <label class="toggle-switch">
+            <input type="checkbox" @bind="_twoFactorEnabled" />
+            <span class="toggle-slider"></span>
+        </label>
+    </div>
+
+    @* Active Sessions *@
+    <h5 class="mt-4">Active Sessions</h5>
+    @if (_security?.Sessions is { Count: > 0 })
+    {
+        <div class="table-responsive">
+            <table class="table table-hover sessions-table">
+                <thead>
+                    <tr>
+                        <th>Device</th>
+                        <th>Location</th>
+                        <th>Last Active</th>
+                        <th></th>
+                    </tr>
+                </thead>
+                <tbody>
+                    @foreach (var session in _security.Sessions)
+                    {
+                        var isCurrentSession = session.Id == _security.Sessions[0].Id;
+                        <tr>
+                            <td>@session.Device</td>
+                            <td>@session.Location</td>
+                            <td>@FormatLastActive(session.LastActive)</td>
+                            <td>
+                                @if (isCurrentSession)
+                                {
+                                    <span class="badge bg-info">Current</span>
+                                }
+                                else
+                                {
+                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => PromptRevokeSession(session)">
+                                        Revoke
+                                    </button>
+                                }
+                            </td>
+                        </tr>
+                    }
+                </tbody>
+            </table>
+        </div>
+    }
+    else
+    {
+        <p class="text-muted">No active sessions.</p>
+    }
+
+    @* Revoke Confirmation Dialog *@
+    @if (_sessionToRevoke is not null)
+    {
+        <div class="modal-overlay" @onclick="() => _sessionToRevoke = null">
+            <div class="confirm-dialog" @onclick:stopPropagation="true">
+                <h5>Revoke Session</h5>
+                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
+                <div class="button-group">
+                    <button class="btn btn-danger" @onclick="ConfirmRevokeSession" disabled="@_saving">
+                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
+                        Revoke
+                    </button>
+                    <button class="btn btn-outline-secondary" @onclick="() => _sessionToRevoke = null">Cancel</button>
+                </div>
+            </div>
+        </div>
+    }
+</section>; }
+
+@* ────────────── Appearance Section ────────────── *@
+@{ RenderFragment RenderAppearanceSection() => @<section class="settings-section">
+    <h3>Appearance</h3>
+    <p class="section-description">Customize how the application looks and feels.</p>
+
+    <h5>Theme</h5>
+    <div class="radio-group">
+        @foreach (var theme in new[] { "Light", "Dark", "System" })
+        {
+            <label class="radio-option">
+                <input type="radio" name="theme" value="@theme" checked="@(_editTheme == theme)" @onchange="() => _editTheme = theme" />
+                <span>@theme</span>
+            </label>
+        }
+    </div>
+
+    <h5 class="mt-3">Font Size</h5>
+    <div class="radio-group">
+        @foreach (var size in new[] { "Small", "Medium", "Large" })
+        {
+            <label class="radio-option">
+                <input type="radio" name="fontSize" value="@size" checked="@(_editFontSize == size)" @onchange="() => _editFontSize = size" />
+                <span>@size</span>
+            </label>
+        }
+    </div>
+
+    <div class="form-group mt-3">
+        <label for="language"><h5 class="d-inline">Language</h5></label>
+        <select id="language" class="form-select mt-1" @bind="_editLanguage">
+            <option value="English">English</option>
+            <option value="Spanish">Spanish</option>
+            <option value="French">French</option>
+            <option value="German">German</option>
+            <option value="Japanese">Japanese</option>
+            <option value="Chinese">Chinese</option>
+        </select>
+    </div>
+
+    <div class="toggle-row mt-3">
+        <div>
+            <strong>Compact Mode</strong>
+            <p class="text-muted small mb-0">Reduce spacing and padding throughout the UI</p>
+        </div>
+        <label class="toggle-switch">
+            <input type="checkbox" @bind="_editCompactMode" />
+            <span class="toggle-slider"></span>
+        </label>
+    </div>
+
+    @* Live Preview *@
+    <h5 class="mt-4">Preview</h5>
+    <div class="appearance-preview @GetPreviewClasses()">
+        <div class="preview-header">Sample Header</div>
+        <p class="preview-text">This is a preview of your selected appearance settings. The theme, font size, and compact mode are reflected here.</p>
+        <div class="preview-buttons">
+            <button class="btn btn-sm btn-primary">Primary</button>
+            <button class="btn btn-sm btn-outline-secondary">Secondary</button>
+        </div>
+    </div>
+
+    <div class="button-group">
+        <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
+            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
+            Save
+        </button>
+    </div>
+</section>; }
+
+@code {
+    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
+    private string _activeSection = "Profile";
+    private bool _loading = true;
+    private bool _saving;
+
+    // Toast
+    private bool _toastVisible;
+    private string _toastMessage = "";
+    private bool _toastIsError;
+
+    // Profile
+    private UserProfile? _savedProfile;
+    private string _editDisplayName = "";
+    private string _editEmail = "";
+    private string _editAvatarUrl = "";
+    private string _editBio = "";
+    private string _profileDisplayName => _editAvatarUrl;
+
+    // Notifications
+    private bool _editEmailNotifications;
+    private bool _editPushNotifications;
+    private bool _editWeeklyDigest;
+    private List<string> _editMutedChannels = [];
+    private readonly List<string> _allChannels = ["general", "announcements", "engineering", "marketing", "support", "random"];
+
+    // Security
+    private SecuritySettings? _security;
+    private bool _twoFactorEnabled;
+    private bool _passwordPanelOpen;
+    private string _currentPassword = "";
+    private string _newPassword = "";
+    private string _confirmPassword = "";
+    private string _passwordError = "";
+    private ActiveSession? _sessionToRevoke;
+
+    // Appearance
+    private string _editTheme = "Light";
+    private string _editFontSize = "Medium";
+    private string _editLanguage = "English";
+    private bool _editCompactMode;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadSectionData();
+    }
+
+    private async Task LoadSectionData()
+    {
+        _loading = true;
+
+        try
+        {
+            switch (_activeSection)
+            {
+                case "Profile":
+                    var profile = await SettingsService.GetProfileAsync();
+                    _savedProfile = profile;
+                    PopulateProfileFields(profile);
+                    break;
+
+                case "Notifications":
+                    var notifs = await SettingsService.GetNotificationPrefsAsync();
+                    _editEmailNotifications = notifs.EmailNotifications;
+                    _editPushNotifications = notifs.PushNotifications;
+                    _editWeeklyDigest = notifs.WeeklyDigest;
+                    _editMutedChannels = new List<string>(notifs.MutedChannels);
+                    break;
+
+                case "Security":
+                    _security = await SettingsService.GetSecuritySettingsAsync();
+                    _twoFactorEnabled = _security.TwoFactorEnabled;
+                    _passwordPanelOpen = false;
+                    _currentPassword = "";
+                    _newPassword = "";
+                    _confirmPassword = "";
+                    _passwordError = "";
+                    _sessionToRevoke = null;
+                    break;
+
+                case "Appearance":
+                    var appearance = await SettingsService.GetAppearanceAsync();
+                    _editTheme = appearance.Theme;
+                    _editFontSize = appearance.FontSize;
+                    _editLanguage = appearance.Language;
+                    _editCompactMode = appearance.CompactMode;
+                    break;
+            }
+        }
+        catch
+        {
+            ShowToast("Failed to load settings.", isError: true);
+        }
+
+        _loading = false;
+    }
+
+    private void PopulateProfileFields(UserProfile profile)
+    {
+        _editDisplayName = profile.DisplayName;
+        _editEmail = profile.Email;
+        _editAvatarUrl = profile.AvatarUrl;
+        _editBio = profile.Bio;
+    }
+
+    private async Task SetActiveSection(string section)
+    {
+        if (_activeSection == section) return;
+        _activeSection = section;
+        await LoadSectionData();
+    }
+
+    // ── Profile ──
+    private async Task SaveProfile()
+    {
+        _saving = true;
+        try
+        {
+            var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
+            await SettingsService.SaveProfileAsync(updated);
+            _savedProfile = updated;
+            ShowToast("Profile saved successfully!");
+        }
+        catch
+        {
+            ShowToast("Failed to save profile.", isError: true);
+        }
+        _saving = false;
+    }
+
+    private void DiscardProfileChanges()
+    {
+        if (_savedProfile is not null)
+        {
+            PopulateProfileFields(_savedProfile);
+        }
+    }
+
+    private static string GetInitials(string name)
+    {
+        if (string.IsNullOrWhiteSpace(name)) return "?";
+        var parts = name.Split(' ', StringSplitOptions.RemoveEmptyEntries);
+        return parts.Length >= 2
+            ? $"{parts[0][0]}{parts[1][0]}".ToUpperInvariant()
+            : parts[0][..1].ToUpperInvariant();
+    }
+
+    // ── Notifications ──
+    private void ToggleMutedChannel(string channel, bool isMuted)
+    {
+        if (isMuted && !_editMutedChannels.Contains(channel))
+            _editMutedChannels.Add(channel);
+        else if (!isMuted)
+            _editMutedChannels.Remove(channel);
+    }
+
+    private async Task SaveNotifications()
+    {
+        _saving = true;
+        try
+        {
+            var prefs = new NotificationPrefs(_editEmailNotifications, _editPushNotifications, _editWeeklyDigest, new List<string>(_editMutedChannels));
+            await SettingsService.SaveNotificationPrefsAsync(prefs);
+            ShowToast("Notification preferences saved!");
+        }
+        catch
+        {
+            ShowToast("Failed to save preferences.", isError: true);
+        }
+        _saving = false;
+    }
+
+    // ── Security ──
+    private async Task ChangePassword()
+    {
+        _passwordError = "";
+
+        if (string.IsNullOrWhiteSpace(_currentPassword))
+        {
+            _passwordError = "Current password is required.";
+            return;
+        }
+        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
+        {
+            _passwordError = "New password must be at least 8 characters.";
+            return;
+        }
+        if (_newPassword != _confirmPassword)
+        {
+            _passwordError = "Passwords do not match.";
+            return;
+        }
+
+        _saving = true;
+        try
+        {
+            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
+            _currentPassword = "";
+            _newPassword = "";
+            _confirmPassword = "";
+            _passwordPanelOpen = false;
+            _security = await SettingsService.GetSecuritySettingsAsync();
+            ShowToast("Password updated successfully!");
+        }
+        catch
+        {
+            ShowToast("Failed to change password.", isError: true);
+        }
+        _saving = false;
+    }
+
+    private void PromptRevokeSession(ActiveSession session)
+    {
+        _sessionToRevoke = session;
+    }
+
+    private async Task ConfirmRevokeSession()
+    {
+        if (_sessionToRevoke is null) return;
+
+        _saving = true;
+        try
+        {
+            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
+            _sessionToRevoke = null;
+            _security = await SettingsService.GetSecuritySettingsAsync();
+            ShowToast("Session revoked.");
+        }
+        catch
+        {
+            ShowToast("Failed to revoke session.", isError: true);
+        }
+        _saving = false;
+    }
+
+    private static string FormatLastActive(DateTime lastActive)
+    {
+        var diff = DateTime.UtcNow - lastActive;
+        if (diff.TotalMinutes < 1) return "Just now";
+        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
+        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
+        return $"{(int)diff.TotalDays}d ago";
+    }
+
+    // ── Appearance ──
+    private string GetPreviewClasses()
+    {
+        var classes = new List<string>();
+        classes.Add($"preview-theme-{_editTheme.ToLowerInvariant()}");
+        classes.Add($"preview-font-{_editFontSize.ToLowerInvariant()}");
+        if (_editCompactMode) classes.Add("preview-compact");
+        return string.Join(" ", classes);
+    }
+
+    private async Task SaveAppearance()
+    {
+        _saving = true;
+        try
+        {
+            var settings = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
+            await SettingsService.SaveAppearanceAsync(settings);
+            ShowToast("Appearance settings saved!");
+        }
+        catch
+        {
+            ShowToast("Failed to save appearance.", isError: true);
+        }
+        _saving = false;
+    }
+
+    // ── Toast ──
+    private async void ShowToast(string message, bool isError = false)
+    {
+        _toastMessage = message;
+        _toastIsError = isError;
+        _toastVisible = true;
+        StateHasChanged();
+
+        await Task.Delay(3000);
+        _toastVisible = false;
+        StateHasChanged();
+    }
+
+    private static string GetSectionIcon(string section) => section switch
+    {
+        "Profile" => "👤",
+        "Notifications" => "🔔",
+        "Security" => "🔒",
+        "Appearance" => "🎨",
+        _ => "⚙️"
+    };
+}
+

toolArgs.file_text:
/* ── Layout ── */
.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    background: #f8f9fa;
    border-radius: 8px;
    overflow: hidden;
    box-shadow: 0 1px 3px rgba(0,0,0,.08);
}

/* ── Sidebar ── */
.settings-sidebar {
    width: 240px;
    min-width: 240px;
    background: #fff;
    border-right: 1px solid #e9ecef;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: .85rem;
    text-transform: uppercase;
    letter-spacing: .05em;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav li {
    display: flex;
    align-items: center;
    gap: .6rem;
    padding: .7rem 1.25rem;
    cursor: pointer;
    color: #495057;
    font-weight: 500;
    transition: background .15s, color .15s;
    border-left: 3px solid transparent;
}

.settings-nav li:hover {
    background: #f1f3f5;
}

.settings-nav li.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
}

.nav-icon {
    font-size: 1.1rem;
}

/* ── Content Area ── */
.settings-content {
    flex: 1;
    padding: 2rem;
    position: relative;
    overflow-y: auto;
}

.settings-section h3 {
    margin: 0 0 .25rem;
    font-weight: 600;
}

.section-description {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

.loading-spinner {
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 200px;
}

/* ── Form Groups ── */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    font-weight: 500;
    margin-bottom: .3rem;
    color: #495057;
}

.button-group {
    display: flex;
    gap: .75rem;
    margin-top: 1.5rem;
}

/* ── Avatar ── */
.avatar-area {
    display: flex;
    align-items: center;
    gap: 1.25rem;
    margin-bottom: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    overflow: hidden;
    background: #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    position: relative;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-fallback {
    position: absolute;
    font-size: 1.5rem;
    font-weight: 700;
    color: #6c757d;
}

.avatar-preview img[src]:not([src=""]) ~ .avatar-fallback {
    display: none;
}

.avatar-url-display {
    min-width: 0;
}

.avatar-url-display label {
    font-weight: 500;
    display: block;
    margin-bottom: .15rem;
    color: #495057;
}

.avatar-url-display span {
    word-break: break-all;
}

/* ── Toggle Switches ── */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 0;
    border-bottom: 1px solid #e9ecef;
}

.toggle-row:last-child {
    border-bottom: none;
}

.toggle-switch {
    position: relative;
    display: inline-block;
    width: 48px;
    height: 26px;
    flex-shrink: 0;
}

.toggle-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.toggle-slider {
    position: absolute;
    cursor: pointer;
    inset: 0;
    background: #ced4da;
    border-radius: 26px;
    transition: background .2s;
}

.toggle-slider::before {
    content: "";
    position: absolute;
    width: 20px;
    height: 20px;
    left: 3px;
    bottom: 3px;
    background: #fff;
    border-radius: 50%;
    transition: transform .2s;
}

.toggle-switch input:checked + .toggle-slider {
    background: #0d6efd;
}

.toggle-switch input:checked + .toggle-slider::before {
    transform: translateX(22px);
}

/* ── Channel List ── */
.channel-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
    gap: .5rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: .5rem;
    padding: .4rem .6rem;
    border-radius: 6px;
    cursor: pointer;
    transition: background .15s;
}

.channel-item:hover {
    background: #f1f3f5;
}

.channel-item input[type="checkbox"] {
    width: 16px;
    height: 16px;
    accent-color: #0d6efd;
}

/* ── Expandable Panel ── */
.expandable-panel {
    border: 1px solid #e9ecef;
    border-radius: 8px;
    overflow: hidden;
}

.panel-header {
    width: 100%;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: .85rem 1rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-weight: 500;
    font-size: .95rem;
    color: #495057;
    transition: background .15s;
}

.panel-header:hover {
    background: #e9ecef;
}

.expand-icon {
    font-size: .75rem;
    color: #6c757d;
}

.panel-body {
    padding: 1rem;
    border-top: 1px solid #e9ecef;
}

/* ── Sessions Table ── */
.sessions-table {
    font-size: .9rem;
}

.sessions-table th {
    font-weight: 600;
    color: #6c757d;
    border-bottom-width: 1px;
    font-size: .8rem;
    text-transform: uppercase;
    letter-spacing: .03em;
}

/* ── Confirmation Dialog ── */
.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.confirm-dialog {
    background: #fff;
    border-radius: 12px;
